static boolean isValidDefineValue(Node val, Set<String> defines) {
  switch (val.getType()) {
    case Token.STRING:
    case Token.NUMBER:
    case Token.TRUE:
    case Token.FALSE:
      return true;

    // Binary operators like ADD, MULTIPLY, etc., require all children to be valid.
    case Token.ADD:
    case Token.BITAND:
    case Token.BITNOT:
    case Token.BITOR:
    case Token.BITXOR:
      for (Node child = val.getFirstChild(); child != null; child = child.getNext()) {
        if (!isValidDefineValue(child, defines)) {
          return false;
        }
      }
      return true;

    // Unary operators are valid if the child is valid.
    case Token.NOT:
    case Token.NEG:
      return val.hasOneChild() && isValidDefineValue(val.getFirstChild(), defines);

    // Names and properties are valid if they refer to defines.
    case Token.NAME:
    case Token.GETPROP:
      return val.isQualifiedName() && defines.contains(val.getQualifiedName());
  }
  return false;
}
